import{_ as a,o as s,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const l=JSON.parse('{"title":"Local DA","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Local DA | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/da-layers/local-da.md","filePath":"guides/da-layers/local-da.md","lastUpdated":1772446570000}');const o=a({name:"guides/da-layers/local-da.md"},[["render",function(a,l,o,t,p,i){return s(),n("div",null,[...l[0]||(l[0]=[e('<h1 id="local-da" tabindex="-1">Local DA <a class="header-anchor" href="#local-da" aria-label="Permalink to &quot;Local DA&quot;">​</a></h1><p>Local DA is a development-only data availability layer for testing Evolve chains without connecting to a real DA network.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Local DA provides:</p><ul><li>Fast, local blob storage</li><li>No authentication required</li><li>No gas fees</li><li>Instant &quot;finality&quot;</li></ul><p><strong>Warning:</strong> Local DA is for development only. It provides no actual data availability guarantees.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install the local-da binary:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> install</span><span style="color:#BFF3C2;"> github.com/evstack/ev-node/tools/local-da@latest</span></span></code></pre></div><p>Or build from source:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ev-node/tools/local-da</span></span>\n<span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> build</span><span style="color:#FFECB6;"> -o</span><span style="color:#BFF3C2;"> local-da</span><span style="color:#BFF3C2;"> .</span></span></code></pre></div><h2 id="running-local-da" tabindex="-1">Running Local DA <a class="header-anchor" href="#running-local-da" aria-label="Permalink to &quot;Running Local DA&quot;">​</a></h2><p>Start the local DA server:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">local-da</span></span></code></pre></div><p>Default output:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF NewLocalDA: initialized LocalDA module=local-da</span></span>\n<span class="line"><span>INF Listening on host=localhost maxBlobSize=1974272 module=da port=7980</span></span>\n<span class="line"><span>INF server started listening on=localhost:7980 module=da</span></span></code></pre></div><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--host</code></td><td><code>localhost</code></td><td>Listen address</td></tr><tr><td><code>--port</code></td><td><code>7980</code></td><td>Listen port</td></tr></tbody></table><p>Example with custom port:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">local-da</span><span style="color:#FFECB6;"> --port</span><span style="color:#FFECB6;"> 8080</span></span></code></pre></div><h2 id="connecting-your-chain" tabindex="-1">Connecting Your Chain <a class="header-anchor" href="#connecting-your-chain" aria-label="Permalink to &quot;Connecting Your Chain&quot;">​</a></h2><p>Start your Evolve chain with the local DA address:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span></code></pre></div><p>For Cosmos SDK chains:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span></code></pre></div><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="no-authentication" tabindex="-1">No Authentication <a class="header-anchor" href="#no-authentication" aria-label="Permalink to &quot;No Authentication&quot;">​</a></h3><p>Unlike Celestia, local DA requires no auth token:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Celestia requires</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.auth_token</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">toke</span><span style="color:#DBD7CA;">n</span><span style="color:#888888;">&gt;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Local DA does not</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span></code></pre></div><h3 id="no-namespace-required" tabindex="-1">No Namespace Required <a class="header-anchor" href="#no-namespace-required" aria-label="Permalink to &quot;No Namespace Required&quot;">​</a></h3><p>Namespace is optional with local DA:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Optional</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.namespace</span><span style="color:#BFF3C2;"> my_namespace</span></span></code></pre></div><h3 id="instant-submission" tabindex="-1">Instant Submission <a class="header-anchor" href="#instant-submission" aria-label="Permalink to &quot;Instant Submission&quot;">​</a></h3><p>Blobs are stored immediately with no block time delay.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="local-development" tabindex="-1">Local Development <a class="header-anchor" href="#local-development" aria-label="Permalink to &quot;Local Development&quot;">​</a></h3><p>Test your chain logic without DA layer complexity:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Terminal 1: Start local DA</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Terminal 2: Start your chain</span></span>\n<span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span></code></pre></div><h3 id="ci-cd-testing" tabindex="-1">CI/CD Testing <a class="header-anchor" href="#ci-cd-testing" aria-label="Permalink to &quot;CI/CD Testing&quot;">​</a></h3><p>Use local DA in automated tests:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Start local DA in background</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span><span style="color:#767676;"> &amp;</span></span>\n<span class="line"><span style="color:#DBD7CA;">LOCAL_DA_PID</span><span style="color:#767676;">=</span><span style="color:#FFECB6;">$!</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Run tests</span></span>\n<span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> test</span><span style="color:#BFF3C2;"> ./...</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Cleanup</span></span>\n<span class="line"><span style="color:#94EEFF;">kill</span><span style="color:#DBD7CA;"> $LOCAL_DA_PID</span></span></code></pre></div><h3 id="integration-testing" tabindex="-1">Integration Testing <a class="header-anchor" href="#integration-testing" aria-label="Permalink to &quot;Integration Testing&quot;">​</a></h3><p>Test multi-node setups locally:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Start local DA</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span><span style="color:#FFECB6;"> --port</span><span style="color:#FFECB6;"> 7980</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Start sequencer</span></span>\n<span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.p2p.listen</span><span style="color:#BFF3C2;"> /ip4/0.0.0.0/tcp/7676</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Start full node (separate terminal)</span></span>\n<span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.p2p.peers</span><span style="color:#BFF3C2;"> /ip4/127.0.0.1/tcp/7676/p2p/</span><span style="color:#888888;">&lt;</span><span style="color:#BFF3C2;">sequencer-peer-i</span><span style="color:#DBD7CA;">d</span><span style="color:#888888;">&gt;</span></span></code></pre></div><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p>Local DA is <strong>not suitable for</strong>:</p><ul><li>Production deployments</li><li>Security testing</li><li>Performance benchmarking (no real network latency)</li><li>Testing DA-specific features (proofs, commitments)</li></ul><h2 id="transitioning-to-celestia" tabindex="-1">Transitioning to Celestia <a class="header-anchor" href="#transitioning-to-celestia" aria-label="Permalink to &quot;Transitioning to Celestia&quot;">​</a></h2><p>When ready for production, switch to Celestia:</p><ol><li>Set up a Celestia light node</li><li>Update your start command:</li></ol><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># From local DA</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># To Celestia</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:26658</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.auth_token</span><span style="color:#DBD7CA;"> $AUTH_TOKEN</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.header_namespace</span><span style="color:#DBD7CA;"> $HEADER_NAMESPACE</span></span>\n<span class="line"><span style="color:#94EEFF;">--evnode.da.data_namespace</span><span style="color:#DBD7CA;"> $DATA_NAMESPACE</span></span></code></pre></div><p>See <a href="/guides/da-layers/celestia">Celestia Guide</a> for full instructions.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guides/da-layers/celestia">Celestia Guide</a> - Production DA setup</li><li><a href="/getting-started/evm/quickstart">EVM Quickstart</a> - Getting started with EVM</li><li><a href="/getting-started/cosmos/quickstart">Cosmos Quickstart</a> - Getting started with Cosmos SDK</li></ul>',54)])])}]]);export{l as __pageData,o as default};
